import type { VNode } from 'vue'

/**
 * header 回调的上下文类型（不含 T，打破递归逆变）
 */
export interface DataTableColumnHeaderContext {
    /** 当前列的 ID */
    id: string
    /** 当前列是否可排序 */
    sortable?: boolean
    /** 当前列的排序方向（null 表示未排序） */
    direction?: 'asc' | 'desc' | null
    /** 当前列的 accessorKey（如果有） */
    accessorKey?: PropertyKey
    /** 当前列的对齐方式 */
    align?: 'left' | 'center' | 'right'
}

export interface DataTableVirtualScroll {
    enabled?: boolean
    rowHeight?: number
}

export interface DataTableColumn<T extends object = Record<string, unknown>> {
    id: string
    /** 函数签名已更新：回调参数从 DataTableColumn<T> 改为 DataTableColumnHeaderContext */
    header: string | ((ctx: DataTableColumnHeaderContext) => string)
    accessorKey?: keyof T & string
    accessorFn?: (row: T) => unknown
    cell?: (props: { row: T; value: unknown }) => VNode | string
    sortable?: boolean
    hidden?: boolean
    width?: number | 'auto'
    minWidth?: number
    maxWidth?: number
    align?: 'left' | 'center' | 'right'
    /** 固定列方向 */
    fixed?: 'left' | 'right'
    /** 列类型 */
    type?: 'default' | 'expand'
}

export interface DataTableSpanMethodParams<T extends object = Record<string, unknown>> {
    row: T
    column: DataTableColumn<T>
    rowIndex: number
    columnIndex: number
}

export interface DataTableProps<T extends object> {
    data: T[]
    columns: DataTableColumn<T>[]
    sortable?: boolean
    filterable?: boolean
    selectable?: boolean
    paginated?: boolean
    pageSize?: number
    pageSizeOptions?: number[]
    loading?: boolean
    emptyMessage?: string
    rowKey: keyof T | ((row: T) => string | number)
    virtualScroll?: DataTableVirtualScroll
    size?: 'sm' | 'default' | 'lg'
    dense?: boolean
    striped?: boolean
    stickyHeader?: boolean
    /** 是否启用展开行 */
    expandable?: boolean
    /** 控制展开的行 */
    expandRowKeys?: Set<string | number>
    /** 合并单元格方法 */
    spanMethod?: (params: DataTableSpanMethodParams<T>) => [number, number] | void
    class?: string
}

export interface DataTableSortState {
    column: string
    direction: 'asc' | 'desc' | null
}

export interface DataTableFilterState {
    global?: string
    columns: Record<string, string>
}

export interface DataTablePaginationState {
    page: number
    pageSize: number
    total: number
}

import { type ComputedRef, type InjectionKey, type MaybeRef, computed, inject, provide, unref } from 'vue'
import { zhCN } from '@/locales/zh-CN'
import type { Locale } from '@/locales/types'

export const LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Locale>> = Symbol('brutx-ui-locale')
export const FALLBACK_LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Partial<Locale>>> = Symbol('brutx-ui-fallback-locale')

export type TranslateFunction = (path: string, params?: Record<string, string | number>) => string

export interface LocaleOptions {
    locale: MaybeRef<Locale>
    fallbackLocale?: MaybeRef<Partial<Locale>>
}

export function provideLocale(localeOrOptions: MaybeRef<Locale> | LocaleOptions): void {
    // 检查是否是 LocaleOptions 格式（包含 locale 属性）
    if (
        typeof localeOrOptions === 'object' &&
        localeOrOptions !== null &&
        'locale' in localeOrOptions
    ) {
        const options = localeOrOptions as LocaleOptions
        provide(LOCALE_INJECTION_KEY, options.locale)
        if (options.fallbackLocale) {
            provide(FALLBACK_LOCALE_INJECTION_KEY, options.fallbackLocale)
        }
    } else {
        // 直接传入 MaybeRef<Locale> 格式（向后兼容）
        provide(LOCALE_INJECTION_KEY, localeOrOptions as MaybeRef<Locale>)
    }
}

function resolveByPath(obj: unknown, path: string): string | undefined {
    const keys = path.split('.')
    let result: unknown = obj
    for (const key of keys) {
        if (typeof result !== 'object' || result === null) return undefined
        result = (result as Record<string, unknown>)[key]
    }
    return typeof result === 'string' ? result : undefined
}

function interpolate(template: string, params?: Record<string, string | number>): string {
    if (!params) return template
    return Object.entries(params).reduce(
        (str, [k, v]) => str.split(`{${k}}`).join(String(v)),
        template,
    )
}

export function useLocale(): { locale: ComputedRef<Locale>; t: TranslateFunction } {
    const injected = inject<MaybeRef<Locale> | undefined>(LOCALE_INJECTION_KEY, undefined)
    const injectedFallback = inject<MaybeRef<Partial<Locale>> | undefined>(FALLBACK_LOCALE_INJECTION_KEY, undefined)

    const locale = computed<Locale>(() => {
        const resolved = injected ? unref(injected) : undefined
        return resolved ?? zhCN
    })

    const fallbackLocale = computed<Partial<Locale>>(() => {
        return injectedFallback ? unref(injectedFallback) : {}
    })

    function t(path: string, params?: Record<string, string | number>): string {
        // 1. 尝试从用户 locale 查找
        const currentVal = resolveByPath(locale.value, path)
        if (currentVal !== undefined) return interpolate(currentVal, params)

        // 2. 尝试从自定义 fallback locale 查找
        if (fallbackLocale.value && Object.keys(fallbackLocale.value).length > 0) {
            const fallbackVal = resolveByPath(fallbackLocale.value, path)
            if (fallbackVal !== undefined) return interpolate(fallbackVal, params)
        }

        // 3. 尝试从默认 zhCN 查找
        const zhCNVal = resolveByPath(zhCN, path)
        if (zhCNVal !== undefined) return interpolate(zhCNVal, params)

        // 4. 返回 path 原文
        return path
    }

    return { locale, t }
}

import { ref, computed, toValue, type MaybeRefOrGetter, type Ref } from 'vue'
import type { DataTableColumn, DataTableSortState } from '@/components/data-table/types'
import { getCellValue } from '@/lib/data-table-utils'

export interface UseDataTableSortOptions<T extends object> {
    columns: MaybeRefOrGetter<DataTableColumn<T>[]>
    sortable: MaybeRefOrGetter<boolean | undefined>
}

export interface UseDataTableSortReturn<T> {
    sortState: Ref<DataTableSortState>
    toggleSort: (columnId: string) => void
    sortedData: (data: T[]) => T[]
}

export function useDataTableSort<T extends object>(
    options: UseDataTableSortOptions<T>,
): UseDataTableSortReturn<T> {
    const sortState = ref<DataTableSortState>({ column: '', direction: null })

    const visibleColumns = computed(() =>
        toValue(options.columns).filter((col) => !col.hidden),
    )
    const isSortable = computed(() => toValue(options.sortable) === true)

    function toggleSort(columnId: string) {
        if (!isSortable.value) return
        const col = visibleColumns.value.find((c) => c.id === columnId)
        if (!col || col.sortable === false) return

        if (sortState.value.column === columnId) {
            if (sortState.value.direction === 'asc') {
                sortState.value = { column: columnId, direction: 'desc' }
            } else if (sortState.value.direction === 'desc') {
                sortState.value = { column: '', direction: null }
            } else {
                sortState.value = { column: columnId, direction: 'asc' }
            }
        } else {
            sortState.value = { column: columnId, direction: 'asc' }
        }
    }

    function sortedData(data: T[]): T[] {
        if (!sortState.value.column || !sortState.value.direction) return data
        const col = visibleColumns.value.find((c) => c.id === sortState.value.column)
        if (!col) return data

        return [...data].sort((a, b) => {
            const valueA = getCellValue(a, col)
            const valueB = getCellValue(b, col)
            if (valueA === valueB) return 0
            if (valueA === null || valueA === undefined) return 1
            if (valueB === null || valueB === undefined) return -1

            if (valueA instanceof Date && valueB instanceof Date) {
                const comparison = valueA.getTime() - valueB.getTime()
                return sortState.value.direction === 'asc' ? comparison : -comparison
            }

            if (typeof valueA === 'number' && typeof valueB === 'number') {
                const comparison = valueA - valueB
                return sortState.value.direction === 'asc' ? comparison : -comparison
            }

            const strA = String(valueA)
            const strB = String(valueB)
            const comparison = strA.localeCompare(strB, undefined, { numeric: true })
            return sortState.value.direction === 'asc' ? comparison : -comparison
        })
    }

    return { sortState, toggleSort, sortedData }
}

import { ref, computed, toValue, type MaybeRefOrGetter, type Ref } from 'vue'
import type { DataTableColumn, DataTableFilterState } from '@/components/data-table/types'
import { getCellValue } from '@/lib/data-table-utils'

export interface UseDataTableFilterOptions<T extends object> {
    columns: MaybeRefOrGetter<DataTableColumn<T>[]>
    filterable: MaybeRefOrGetter<boolean | undefined>
}

export interface UseDataTableFilterReturn<T> {
    filterState: Ref<DataTableFilterState>
    filteredData: (data: T[]) => T[]
}

export function useDataTableFilter<T extends object>(
    options: UseDataTableFilterOptions<T>,
): UseDataTableFilterReturn<T> {
    const filterState = ref<DataTableFilterState>({ global: '', columns: {} })

    const visibleColumns = computed(() =>
        toValue(options.columns).filter((col) => !col.hidden),
    )
    const isFilterable = computed(() => toValue(options.filterable) === true)

    function filteredData(data: T[]): T[] {
        if (!isFilterable.value) return data

        let result = [...data]

        if (filterState.value.global) {
            const search = filterState.value.global.toLowerCase()
            result = result.filter((row) =>
                visibleColumns.value.some((col) =>
                    String(getCellValue(row, col)).toLowerCase().includes(search),
                ),
            )
        }

        Object.entries(filterState.value.columns).forEach(([columnId, filterValue]) => {
            if (filterValue === undefined || filterValue === null || filterValue === '') return
            const col = visibleColumns.value.find((c) => c.id === columnId)
            if (!col) return
            result = result.filter((row) =>
                String(getCellValue(row, col)).toLowerCase().includes(String(filterValue).toLowerCase()),
            )
        })

        return result
    }

    return { filterState, filteredData }
}

import { shallowRef, computed, toValue, type ComputedRef, type MaybeRefOrGetter, type ShallowRef } from 'vue'

export interface UseDataTableSelectionOptions<T extends object> {
    selectable: MaybeRefOrGetter<boolean | undefined>
    rowKey: MaybeRefOrGetter<keyof T | ((row: T) => string | number)>
    displayData: MaybeRefOrGetter<T[]>
    data: MaybeRefOrGetter<T[]>
}

export interface UseDataTableSelectionReturn<T> {
    selectedRows: ShallowRef<Set<string | number>>
    isAllSelected: ComputedRef<boolean>
    isIndeterminate: ComputedRef<boolean>
    toggleRowSelection: (row: T) => void
    toggleAllSelection: () => void
    clearSelection: () => void
    getRowKey: (row: T) => string | number
    getSelectedRows: () => T[]
}

export function useDataTableSelection<T extends object>(
    options: UseDataTableSelectionOptions<T>,
): UseDataTableSelectionReturn<T> {
    const selectedRows = shallowRef<Set<string | number>>(new Set())

    function getRowKey(row: T): string | number {
        const key = toValue(options.rowKey)
        if (typeof key === 'function') return key(row)
        const value = row[key]
        if (typeof value !== 'string' && typeof value !== 'number') {
            console.warn(`[useDataTableSelection] rowKey property "${String(key)}" returned a non-string/number value. Using String conversion.`)
            return String(value)
        }
        return value
    }

    const isAllSelected = computed(() => {
        const data = toValue(options.displayData)
        if (data.length === 0) return false
        return data.every((row) => selectedRows.value.has(getRowKey(row)))
    })

    const isIndeterminate = computed(() => {
        if (isAllSelected.value) return false
        const data = toValue(options.displayData)
        return data.some((row) => selectedRows.value.has(getRowKey(row)))
    })

    function toggleRowSelection(row: T) {
        if (toValue(options.selectable) !== true) return
        const key = getRowKey(row)
        const newSelection = new Set(selectedRows.value)
        if (newSelection.has(key)) {
            newSelection.delete(key)
        } else {
            newSelection.add(key)
        }
        selectedRows.value = newSelection
    }

    function toggleAllSelection() {
        if (toValue(options.selectable) !== true) return
        if (isAllSelected.value) {
            selectedRows.value = new Set()
        } else {
            const newSelection = new Set(selectedRows.value)
            toValue(options.displayData).forEach((row) => newSelection.add(getRowKey(row)))
            selectedRows.value = newSelection
        }
    }

    function clearSelection() {
        selectedRows.value = new Set()
    }

    function getSelectedRows(): T[] {
        return toValue(options.data).filter((row) => selectedRows.value.has(getRowKey(row)))
    }

    return {
        selectedRows,
        isAllSelected,
        isIndeterminate,
        toggleRowSelection,
        toggleAllSelection,
        clearSelection,
        getRowKey,
        getSelectedRows,
    }
}

import { ref, computed, watch, toValue, type ComputedRef, type MaybeRefOrGetter, type Ref } from 'vue'

export const DEFAULT_PAGE_SIZE = 10

export interface UseDataTablePaginationOptions {
    paginated: MaybeRefOrGetter<boolean | undefined>
    pageSize: MaybeRefOrGetter<number | undefined>
    totalItems: MaybeRefOrGetter<number>
}

export interface UseDataTablePaginationReturn {
    currentPage: Ref<number>
    currentPageSize: Ref<number>
    totalPages: ComputedRef<number>
    paginatedData: <T>(data: T[]) => T[]
    goToPage: (page: number) => boolean
    setPageSize: (size: number) => void
}

export function useDataTablePagination(options: UseDataTablePaginationOptions): UseDataTablePaginationReturn {
    const currentPage = ref(1)
    const currentPageSize = ref(toValue(options.pageSize) ?? DEFAULT_PAGE_SIZE)

    const totalPages = computed(() => {
        const total = toValue(options.totalItems)
        return Math.max(1, Math.ceil(total / currentPageSize.value))
    })

    watch(() => toValue(options.pageSize), (newSize) => {
        currentPageSize.value = newSize ?? DEFAULT_PAGE_SIZE
    })

    watch(totalPages, (newTotal) => {
        if (currentPage.value > newTotal) {
            currentPage.value = Math.max(1, newTotal)
        }
    })

    function paginatedData<T>(data: T[]): T[] {
        if (toValue(options.paginated) !== true) return data
        const start = (currentPage.value - 1) * currentPageSize.value
        return data.slice(start, start + currentPageSize.value)
    }

    function goToPage(page: number): boolean {
        const newPage = Math.max(1, Math.min(page, totalPages.value))
        if (newPage !== currentPage.value) {
            currentPage.value = newPage
            return true
        }
        return false
    }

    function setPageSize(size: number) {
        currentPageSize.value = size
        currentPage.value = 1
    }

    return { currentPage, currentPageSize, totalPages, paginatedData, goToPage, setPageSize }
}

